CREATE or ALTER PROCEDURE [integration].[sp_UpsertDomainTable]
    @DomainName VARCHAR(100),
    @LayerKey VARCHAR(50),
    @SchemaName NVARCHAR(128),
    @TableName NVARCHAR(128),
    @EnvironmentName VARCHAR(50) = NULL,
    @DisplayName NVARCHAR(200) = NULL,
    @Description NVARCHAR(400) = NULL,
    @Classification VARCHAR(50) = NULL,
    @SensitivityTag NVARCHAR(100) = NULL,
    @HasSensitiveData BIT = NULL,
    @RetentionPolicy VARCHAR(100) = NULL,
    @RetentionDays INT = NULL,
    @DataQualityRuleset VARCHAR(100) = NULL,
    @Tags NVARCHAR(400) = NULL,
    @IsActive BIT = 1
WITH EXECUTE AS CALLER
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @DomainLayerId INT;
    SELECT @DomainLayerId = DL.[DomainLayerId]
    FROM [integration].[Domain] D
    INNER JOIN [integration].[DomainLayer] DL ON DL.[DomainId] = D.[DomainId]
    WHERE D.[Name] = @DomainName
      AND DL.[LayerKey] = @LayerKey;

    IF @DomainLayerId IS NULL
    BEGIN
        THROW 50008, 'Domain layer not found', 1;
    END

    DECLARE @Output TABLE (DomainTableId INT);

    IF EXISTS (SELECT 1 FROM [integration].[DomainTable]
              WHERE [DomainLayerId] = @DomainLayerId
                AND [SchemaName] = @SchemaName
                AND [TableName] = @TableName
                AND ISNULL([EnvironmentName], '') = ISNULL(@EnvironmentName, ''))
    BEGIN
        UPDATE [integration].[DomainTable]
        SET [DisplayName] = @DisplayName,
            [Description] = @Description,
            [Classification] = @Classification,
            [SensitivityTag] = @SensitivityTag,
            [HasSensitiveData] = @HasSensitiveData,
            [RetentionPolicy] = @RetentionPolicy,
            [RetentionDays] = @RetentionDays,
            [DataQualityRuleset] = @DataQualityRuleset,
            [Tags] = @Tags,
            [IsActive] = @IsActive
        OUTPUT INSERTED.[DomainTableId] INTO @Output
        WHERE [DomainLayerId] = @DomainLayerId
          AND [SchemaName] = @SchemaName
          AND [TableName] = @TableName
          AND ISNULL([EnvironmentName], '') = ISNULL(@EnvironmentName, '');
    END
    ELSE
    BEGIN
        INSERT INTO [integration].[DomainTable]
            ([DomainLayerId], [EnvironmentName], [SchemaName], [TableName], [DisplayName], [Description],
             [Classification], [SensitivityTag], [HasSensitiveData], [RetentionPolicy], [RetentionDays],
             [DataQualityRuleset], [Tags], [IsActive])
        OUTPUT INSERTED.[DomainTableId] INTO @Output
        VALUES (@DomainLayerId, @EnvironmentName, @SchemaName, @TableName, @DisplayName, @Description,
                @Classification, @SensitivityTag, @HasSensitiveData, @RetentionPolicy, @RetentionDays,
                @DataQualityRuleset, @Tags, @IsActive);
    END

    SELECT DomainTableId FROM @Output;
END
